SELECT COUNT(*) AS QUANTIDADE FROM SERVIDOR_PROJ SP JOIN SERVIDOR S ON SP.FK_SIAPE = S.PK_SIAPE JOIN PROJ P ON SP.FK_PROJ = P.PK WHERE LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('gyn') AND LOWER(SP.PAPEL) = LOWER('autor') AND LOWER(P.TIPO_PROJETO) = LOWER('pesquisa') AND LOWER(COALESCE(P.AREA_CONHECIMENTO, '')) LIKE '%engenharia civil%' AND SP.DATA_SAIDA >= DATE('now', '-5 years') AND SP.DATA_ENTRADA <= DATE('now')